echo "$TOOL_INPUT" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    path = data.get('file_path', data.get('filePath', ''))
    vault = 'iCloud~md~obsidian/Documents/Obsidian Vault'
    if vault in path:
        # Inside vault - gentle reminder about markdown format
        if path.endswith('.md'):
            print('Writing to Obsidian vault. Use [[wikilinks]] for internal links, not [text](path). Use callout syntax (> [!type]) for admonitions. Preserve existing frontmatter YAML.')
        else:
            print('')
    else:
        print('')
except:
    print('')
" 2>/dev/null || echo ''

